import type React from 'react';

import { Button } from '../button';
import {
  EmptyState,
  EmptyStateDescription,
  EmptyStateTitle,
} from '../empty-state';
import { Skeleton } from '../skeleton';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '../table';
import { cn } from '../utils/cn';

type Column<T> = {
  id: string;
  header: string;
  accessor: (row: T) => React.ReactNode;
  sortable?: boolean;
  width?: string;
  align?: 'left' | 'center' | 'right';
};

type DataTableProps<T> = {
  columns: Column<T>[];
  data: T[];
  sortBy?: string;
  sortDirection?: 'asc' | 'desc';
  onSort?: (columnId: string) => void;
  isLoading?: boolean;
  loadingRows?: number;
  emptyMessage?: string;
  emptyDescription?: string;
  className?: string;
};

const alignClassMap = {
  left: 'text-left',
  center: 'text-center',
  right: 'text-right',
} as const;

function SortIcon({
  active,
  direction,
}: {
  active: boolean;
  direction?: 'asc' | 'desc';
}) {
  if (!active) {
    return (
      <svg
        aria-hidden="true"
        className="ml-1 inline-block size-4 text-muted-foreground/50"
        viewBox="0 0 16 16"
        fill="currentColor"
      >
        <path d="M8 4l3 4H5l3-4zm0 8L5 8h6l-3 4z" />
      </svg>
    );
  }

  if (direction === 'asc') {
    return (
      <svg
        aria-hidden="true"
        className="ml-1 inline-block size-4"
        viewBox="0 0 16 16"
        fill="currentColor"
      >
        <path d="M8 4l4 5H4l4-5z" />
      </svg>
    );
  }

  return (
    <svg
      aria-hidden="true"
      className="ml-1 inline-block size-4"
      viewBox="0 0 16 16"
      fill="currentColor"
    >
      <path d="M8 12l-4-5h8l-4 5z" />
    </svg>
  );
}

/**
 * A sortable data table composing Table, Skeleton, and EmptyState.
 *
 * Accepts typed column definitions with accessor functions for extracting
 * cell content. Supports controlled sorting, loading skeleton rows,
 * and an empty state when no data is available.
 */
function DataTable<T>({
  columns,
  data,
  sortBy,
  sortDirection,
  onSort,
  isLoading = false,
  loadingRows = 5,
  emptyMessage = 'No data available',
  emptyDescription,
  className,
}: DataTableProps<T>) {
  return (
    <div data-slot="data-table" className={cn(className)}>
      <Table>
        <TableHeader>
          <TableRow>
            {columns.map((column) => (
              <TableHead
                key={column.id}
                style={column.width ? { width: column.width } : undefined}
                className={column.align ? alignClassMap[column.align] : undefined}
              >
                {column.sortable && onSort ? (
                  <Button
                    variant="text"
                    size="sm"
                    onClick={() => onSort(column.id)}
                    className="-ml-2 font-medium"
                  >
                    {column.header}
                    <SortIcon
                      active={sortBy === column.id}
                      direction={sortBy === column.id ? sortDirection : undefined}
                    />
                  </Button>
                ) : (
                  column.header
                )}
              </TableHead>
            ))}
          </TableRow>
        </TableHeader>
        <TableBody>
          {isLoading
            ? Array.from({ length: loadingRows }, (_, rowIndex) => (
                <TableRow key={`skeleton-${rowIndex}`}>
                  {columns.map((column) => (
                    <TableCell
                      key={column.id}
                      className={
                        column.align ? alignClassMap[column.align] : undefined
                      }
                    >
                      <Skeleton className="h-4 w-3/4" />
                    </TableCell>
                  ))}
                </TableRow>
              ))
            : data.length === 0
              ? null
              : data.map((row, rowIndex) => (
                  <TableRow key={rowIndex}>
                    {columns.map((column) => (
                      <TableCell
                        key={column.id}
                        className={
                          column.align ? alignClassMap[column.align] : undefined
                        }
                      >
                        {column.accessor(row)}
                      </TableCell>
                    ))}
                  </TableRow>
                ))}
        </TableBody>
      </Table>
      {!isLoading && data.length === 0 && (
        <EmptyState>
          <EmptyStateTitle>{emptyMessage}</EmptyStateTitle>
          {emptyDescription && (
            <EmptyStateDescription>{emptyDescription}</EmptyStateDescription>
          )}
        </EmptyState>
      )}
    </div>
  );
}

export { DataTable };
export type { Column, DataTableProps };
